@charset "UTF-8";
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: Inter, Segoe UI, Roboto, Helvetica, Arial, sans-serif;
  font-size: 13px;
  background: transparent;
  color: #1F2937;
}

.widget-container {
  background: #FFFFFF;
  border: 1px solid #E5E7EB;
  border-radius: 16px;
  padding: 18px;
  box-shadow: 0 2px 6px rgba(15, 23, 42, 0.04), 0 8px 24px rgba(15, 23, 42, 0.04);
}

.widget-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16px;
  padding-bottom: 14px;
  border-bottom: 1px solid #F3F4F6;
}

.header-title {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 16px;
  font-weight: 700;
  color: #111827;
}

.header-icon {
  display: flex;
  justify-content: center;
  align-items: center;
  width: 34px;
  height: 34px;
  border-radius: 10px;
  background: #EEF4FF;
  font-size: 18px;
}

/* ── ROW LAYOUT ── */
.division-row {
  display: flex;
  flex-direction: row;
  gap: 8px;
  overflow-x: auto;
  padding-bottom: 4px;
}

.chip {
  flex: 1;
  min-width: 110px;
  background: #FFFFFF;
  border: 1px solid #E5E7EB;
  border-radius: 12px;
  padding: 12px 10px;
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 10px;
  transition: 0.2s;
  box-shadow: 0 2px 6px rgba(15, 23, 42, 0.03);
}

.chip:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 20px rgba(15, 23, 42, 0.08);
}

.chip-name {
  font-size: 11px;
  font-weight: 600;
  color: #6B7280;
  letter-spacing: 0.2px;
  white-space: nowrap;
}

.chip-footer {
  width: 100%;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

/* ── BADGES ── */
.badge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 3px 8px;
  border-radius: 999px;
  font-size: 10px;
  font-weight: 600;
  white-space: nowrap;
  border: 1px solid transparent;
}

.badge-SUBMITTED {
  background: #EAF7ED;
  color: #217A3D;
  border-color: #BEE5C8;
}

.badge-IN_WORK {
  background: #EAF4FF;
  color: #1565C0;
  border-color: #BFD9FF;
}

.badge-REWORK {
  background: #FFF5E6;
  color: #A85A00;
  border-color: #FFD38A;
}

.badge-NOT_STARTED {
  background: #F5F6F8;
  color: #6B7280;
  border-color: #E5E7EB;
}

/* ── BUTTONS ── */
button {
  transition: 0.2s;
  font-family: inherit;
}

.btn-rework {
  width: 100%;
  padding: 5px 0;
  border-radius: 7px;
  border: 1px solid #EF4444;
  background: #FFFFFF;
  color: #DC2626;
  font-size: 10px;
  font-weight: 600;
  cursor: pointer;
}

.btn-rework:hover:not(:disabled) {
  background: #FEF2F2;
}

.btn-rework:disabled {
  opacity: 0.35;
  cursor: not-allowed;
}

.btn-rework-all,
.btn-view-concern,
.btn-release {
  width: 100%;
  height: 40px;
  border-radius: 10px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
}

.btn-rework-all {
  margin-top: 14px;
  border: 1px solid #EF4444;
  background: #FEF2F2;
  color: #DC2626;
}

.btn-rework-all:hover:not(:disabled) {
  background: #FEE2E2;
}

.btn-rework-all:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

.btn-view-concern {
  margin-top: 8px;
  border: 1px solid #3B82F6;
  background: #EFF6FF;
  color: #2563EB;
}

.btn-view-concern:hover {
  background: #DBEAFE;
}

.btn-release {
  margin-top: 10px;
  border: none;
  color: #FFFFFF;
  background: linear-gradient(90deg, #16A34A, #22C55E);
  box-shadow: 0 6px 16px rgba(34, 197, 94, 0.25);
}

.btn-release:hover:not(:disabled) {
  transform: translateY(-1px);
}

.btn-release:disabled {
  opacity: 0.45;
  box-shadow: none;
  cursor: not-allowed;
}

/* ── BANNER ── */
.banner {
  margin-top: 12px;
  padding: 12px 14px;
  border-radius: 10px;
  font-size: 12px;
  line-height: 1.6;
  font-weight: 500;
  border: 1px solid transparent;
}

.banner-success {
  background: #ECFDF5;
  color: #047857;
  border-color: #A7F3D0;
}

.banner-warning {
  background: #FFF7ED;
  color: #B45309;
  border-color: #FCD34D;
}

#footer {
  margin-top: 14px;
}

.empty-state {
  text-align: center;
  color: #9CA3AF;
  padding: 30px 20px;
  font-size: 13px;
}

::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

::-webkit-scrollbar-thumb {
  background: #D1D5DB;
  border-radius: 999px;
}

::-webkit-scrollbar-thumb:hover {
  background: #9CA3AF;
}

