appsmith.onReady(function () {
  render();
  appsmith.onModelChange(render);
});
const DIVISION_LABEL = {
  BLACKBOX: 'Blackbox',
  COMMERZ: 'Commerz',
  COS: 'COS',
  UPPER_TOOLING: 'Upper Treatment',
  BOTTOM_ENGINEERING: 'Bottom Eng.'
};
const STATUS_ICON = {
  SUBMITTED: '✅',
  IN_WORK: '🔄',
  REWORK: '⚠️',
  NOT_STARTED: '⚪'
};
function createButton(className, text, disabled, onClick) {
  const btn = document.createElement('button');
  btn.className = className;
  btn.textContent = text;
  btn.disabled = disabled;
  if (onClick) btn.addEventListener('click', onClick);
  return btn;
}
function render() {
  const {
    statuses = [],
    readiness = '',
    canRelease = false
  } = appsmith.model;
  const root = document.getElementById('root');
  const footer = document.getElementById('footer');
  footer.innerHTML = '';
  if (!statuses.length) {
    root.innerHTML = '<div class="empty-state">📋<br><br>Pilih article terlebih dahulu</div>';
    return;
  }

  // ── Chip row ──
  root.innerHTML = '<div class="division-row" id="divisionRow"></div>';
  const row = document.getElementById('divisionRow');
  const DIVISION_ORDER = ['BLACKBOX', 'COMMERZ', 'COS', 'UPPER_TOOLING', 'BOTTOM_ENGINEERING'];
  DIVISION_ORDER.forEach(function (divKey) {
    const s = statuses.find(function (x) {
      return x.division === divKey;
    });
    const state = s ? s.state : 'NOT_STARTED';
    const isSubmitted = state === 'SUBMITTED';
    const chip = document.createElement('div');
    chip.className = 'chip';
    const name = document.createElement('div');
    name.className = 'chip-name';
    name.textContent = DIVISION_LABEL[divKey] || divKey;
    const chipFooter = document.createElement('div');
    chipFooter.className = 'chip-footer';
    const badge = document.createElement('span');
    badge.className = 'badge badge-' + state;
    badge.textContent = (STATUS_ICON[state] || '') + ' ' + state.replace(/_/g, ' ');
    const btnRework = createButton('btn-rework', '↩ Rework', !isSubmitted, function () {
      appsmith.updateModel({
        selectedDivision: divKey,
        reworkAll: false
      });
      setTimeout(function () {
        appsmith.triggerEvent('onReworkClick');
      }, 100);
    });
    chipFooter.appendChild(badge);
    chipFooter.appendChild(btnRework);
    chip.appendChild(name);
    chip.appendChild(chipFooter);
    row.appendChild(chip);
  });

  // ── Footer ──
  const anySubmitted = statuses.some(function (s) {
    return s.state === 'SUBMITTED';
  });
  const btnReworkAll = createButton('btn-rework-all', '↩ Rework All Division', !anySubmitted, function () {
    appsmith.updateModel({
      selectedDivision: null,
      reworkAll: true
    });
    setTimeout(function () {
      appsmith.triggerEvent('onReworkClick');
    }, 100);
  });
  const btnViewConcern = createButton('btn-view-concern', '💬 View Concern', false, function () {
    appsmith.triggerEvent('onViewConcernClick');
  });
  const banner = document.createElement('div');
  banner.className = 'banner ' + (canRelease ? 'banner-success' : 'banner-warning');
  banner.textContent = readiness || '—';
  const btnRelease = createButton('btn-release', '🚀 Release Article', !canRelease, function () {
    appsmith.triggerEvent('onReleaseClick');
  });
  footer.appendChild(btnReworkAll);
  footer.appendChild(btnViewConcern);
  footer.appendChild(banner);
  footer.appendChild(btnRelease);
}

